with open(r'c:\Users\goura\OneDrive\Desktop\Startup\accoplacers\django-acco\base\views.py', 'a') as f:
    f.write("\n\ndef job_detail(request, pk):\n    from django.shortcuts import get_object_or_404\n    job = get_object_or_404(JobOpening, pk=pk, is_active=True)\n    \n    if request.GET.get('format') == 'md':\n        content = f\"# {job.title}\\n\\n\"\n        content += f\"**Location:** {job.location}\\n\"\n        content += f\"**Job Type:** {job.job_type}\\n\"\n        if job.salary_range:\n            content += f\"**Salary:** {job.salary_range}\\n\"\n        content += f\"**Company:** {job.employer.company_name}\\n\\n\"\n        content += \"## Description\\n\"\n        content += f\"{job.description}\\n\\n\"\n        content += \"## Requirements\\n\"\n        content += f\"{job.requirements}\\n\"\n        \n        return HttpResponse(content, content_type='text/markdown')\n    \n    return render(request, 'base/job_detail.html', {'job': job})\n")
